using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
int a, n, m, x, ans, fbzq[25], qzh[25];
int main(void)
{
	cin >> a >> n >> m >> x;
	ans = a * (1 + (x > 2));
	if (x >= 4)
	{
		fbzq[1] = fbzq[2] = 1;
		for (int i = 3; i <= n; ++i)fbzq[i] = fbzq[i - 1] + fbzq[i - 2];
		for (int i = 1; i <= n; ++i)qzh[i] = qzh[i - 1] + fbzq[i];
		ans += qzh[x - 4] * a + qzh[x - 3] * ((m - qzh[n - 5] * a - ans) / qzh[n - 4]);
	}
	cout << ans;
	return false;
}
